mapper.select:
SELECT id, content, metadata, (1 - (embedding <=> #{queryVec}::vector)) * 0.7 + COALESCE( ts_rank(to_tsvector('simple', content), to_tsquery('simple', #{tsQuery})), 0 ) * 0.3 AS hybrid_score FROM public.vector_store WHERE (1 - (embedding <=> #{queryVec}::vector)) >= 0.6
AND metadata ->> 'knowledgeType' = #{category}
ORDER BY hybrid_score DESC LIMIT #{topK}

SELECT * FROM knowledge_bases
WHERE user_id = #{userId} AND knowledge_type = #{type}
ORDER BY created_at DESC

SELECT * FROM knowledge_bases
WHERE user_id = #{userId} AND file_name = #{fileName}
ORDER BY chunk_index ASC

SELECT *
FROM knowledge_bases
WHERE knowledge_type = #{knowledgeType}
ORDER BY embedding <=> #{vecStr}::vector
LIMIT #{limit}

SELECT *
FROM knowledge_bases
WHERE user_id = #{userId}
  AND knowledge_type = 'USER'
ORDER BY embedding <=> #{vecStr}::vector
LIMIT #{limit}

